class Solution {
public:
    void dfs(int node, int par, long long s, int target_sum,
             vector<vector<int>> &adj, vector<int> &degree, bool &check) {
        s += node;

        for (int v : adj[node]) {
            if (v != par) dfs(v, node, s, target_sum, adj, degree, check);
        }

        if (par != -1 && degree[node] == 1) {
            if (s == target_sum) check = true;
        }
    }

    bool solution(int n, int target_sum, vector<vector<int>> &adj) {
        if (n == 1) return target_sum == 1;

        vector<int> degree(n + 1, 0);
        for (int i = 1; i <= n; i++) {
            degree[i] = adj[i].size();
        }

        bool check = false;
        dfs(1, -1, 0, target_sum, adj, degree, check);
        return check;
    }
};

