void dfs(Solution* sol, int node, int parent, long long s,
         int target_sum,
         int** adj, int* adjSize,
         int* degree,
         int* check)
{
    s += node;

    for (int i = 0; i < adjSize[node]; i++) {
        int v = adj[node][i];
        if (v != parent) {
            dfs(sol, v, node, s, target_sum, adj, adjSize, degree, check);
        }
    }

    if (parent != -1 && degree[node] == 1) {
        if (s == target_sum) *check = 1;
    }
}

int solution(Solution* sol, int n, int target_sum,
             int** adj, int* adjSize)
{
    int* degree = (int*)calloc(n + 1, sizeof(int));

    for (int i = 1; i <= n; i++) {
        degree[i] = adjSize[i];
    }

    if (n == 1) {
        free(degree);
        return target_sum == 1;
    }

    int check = 0;

    dfs(sol, 1, -1, 0, target_sum, adj, adjSize, degree, &check);

    free(degree);
    return check;
}

