class Solution {

    dfs(node, parent, s, target_sum, adj, degree, check) {
        s += node;

        for (const v of adj[node]) {
            if (v !== parent) {
                this.dfs(v, node, s, target_sum, adj, degree, check);
            }
        }

        if (parent !== -1 && degree[node] === 1) {
            if (s === target_sum) check.value = true;
        }
    }

    solution(n, target_sum, adj) {
        if (n === 1) return target_sum === 1;

        const degree = new Array(n + 1).fill(0);
        for (let i = 1; i <= n; i++) {
            degree[i] = adj[i].length;
        }

        const check = { value: false };
        this.dfs(1, -1, 0, target_sum, adj, degree, check);
        return check.value;
    }
}
